const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find eligible T-shirts: apparel, t_shirt, active, M available, price <= 30
const eligibleTees = products.filter(p => {
  return p && p.status === 'active' && p.categoryId === 'apparel' && p.subtype === 't_shirt' &&
    typeof p.price === 'number' && p.price <= 30 &&
    Array.isArray(p.sizesAvailable) && p.sizesAvailable.includes('m');
});

// Sort by price ascending, then by createdAt ascending for stability
eligibleTees.sort((a, b) => {
  const pa = a.price || 0;
  const pb = b.price || 0;
  if (pa !== pb) return pa - pb;
  const da = new Date(a.createdAt || 0).getTime();
  const db = new Date(b.createdAt || 0).getTime();
  return da - db;
});

const cheapestTwo = eligibleTees.slice(0, 2);
const cheapestIdsSet = new Set(cheapestTwo.map(p => p.id));

// Check cart for those specific products with selectedSize 'm'
const qualifyingCartProductIds = new Set();
cartItems.forEach(item => {
  if (!item) return;
  if (item.itemType === 'product' && item.quantity > 0 && item.selectedSize === 'm' && cheapestIdsSet.has(item.productId)) {
    qualifyingCartProductIds.add(item.productId);
  }
});

const qualifyingCount = qualifyingCartProductIds.size;

// CP1 (0.4): At least one of the two cheapest qualifying tees in size M is in the cart
checkpoints.push({ passed: qualifyingCount >= 1, weight: 0.4 });

// CP2 (0.6): Both of the two cheapest qualifying tees in size M are in the cart
checkpoints.push({ passed: qualifyingCount >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const videos = JSON.parse(localStorage.getItem('videos') || '[]');
const playlists = JSON.parse(localStorage.getItem('playlists') || '[]');
const playlistItems = JSON.parse(localStorage.getItem('playlist_items') || '[]');

// All qualifying music videos (published, type music_video, year >= 2023)
const qualifyingVideos = videos.filter(v => {
  if (!v || v.status !== 'published' || v.videoType !== 'music_video') return false;
  const d = new Date(v.releaseDate);
  if (isNaN(d.getTime())) return false;
  return d.getUTCFullYear() >= 2023;
});

let newestVideo = null;
if (qualifyingVideos.length > 0) {
  newestVideo = qualifyingVideos.slice().sort((a, b) => new Date(b.releaseDate) - new Date(a.releaseDate))[0];
}

// Find Favorites playlist (system favorites first, then by name)
let favoritesPlaylist = playlists.find(pl => pl && pl.isSystem === true && pl.systemType === 'favorites');
if (!favoritesPlaylist) {
  favoritesPlaylist = playlists.find(pl => (pl.name || '').toLowerCase() === 'favorites');
}

let qualifyingInFavorites = [];
let newestInFavorites = false;

if (favoritesPlaylist && newestVideo) {
  const favItems = playlistItems.filter(it => it && it.playlistId === favoritesPlaylist.id && it.contentType === 'video');

  qualifyingInFavorites = favItems.filter(it => {
    const video = videos.find(v => v.id === it.videoId);
    if (!video) return false;
    if (video.status !== 'published' || video.videoType !== 'music_video') return false;
    const d = new Date(video.releaseDate);
    if (isNaN(d.getTime())) return false;
    return d.getUTCFullYear() >= 2023;
  });

  newestInFavorites = qualifyingInFavorites.some(it => it.videoId === newestVideo.id);
}

// CP1 (0.4): At least one qualifying (2023+, music_video) video was added to Favorites
checkpoints.push({ passed: qualifyingInFavorites.length >= 1, weight: 0.4 });

// CP2 (0.6): The newest qualifying music video was added to Favorites
checkpoints.push({ passed: newestInFavorites, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const playlists = JSON.parse(localStorage.getItem('playlists') || '[]');
const playlistItems = JSON.parse(localStorage.getItem('playlist_items') || '[]');
const tracks = JSON.parse(localStorage.getItem('tracks') || '[]');

// Find playlist named 'Workout Mix'
const workoutPlaylist = playlists.find(pl => (pl.name || '').toLowerCase() === 'workout mix');

// CP1 (0.3): Playlist with the correct name exists
checkpoints.push({ passed: !!workoutPlaylist, weight: 0.3 });

let durationOk = false;
let threeAlbums = false;

if (workoutPlaylist) {
  const items = playlistItems.filter(it => it && it.playlistId === workoutPlaylist.id && it.contentType === 'track');
  const detailedTracks = items
    .map(it => tracks.find(t => t.id === it.trackId))
    .filter(t => !!t && typeof t.durationSeconds === 'number');

  const trackCount = detailedTracks.length;
  const allDurationsWithinRange = detailedTracks.every(t => t.durationSeconds >= 180 && t.durationSeconds <= 300);

  durationOk = (trackCount === 5 && allDurationsWithinRange);

  const albumIdSet = new Set(detailedTracks.map(t => t.albumId).filter(Boolean));
  threeAlbums = (durationOk && albumIdSet.size >= 3);
}

// CP2 (0.3): Playlist has exactly 5 tracks, all between 3 and 5 minutes
checkpoints.push({ passed: durationOk, weight: 0.3 });

// CP3 (0.4): Those 5 tracks come from at least 3 distinct albums
checkpoints.push({ passed: threeAlbums, weight: 0.4 });

return checkPointsTotal = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const ticketTypes = JSON.parse(localStorage.getItem('ticket_types') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Find LA events in August 2025 with tickets on sale
const laAugEvents = events.filter(e => {
  if (!e || !e.ticketsOnSale) return false;
  if ((e.city || '').toLowerCase() !== 'los angeles') return false;
  const d = new Date(e.eventDateTime);
  if (isNaN(d.getTime())) return false;
  return d.getUTCFullYear() === 2025 && (d.getUTCMonth() + 1) === 8;
});

let targetTicketTypeId = null;

if (laAugEvents.length > 0) {
  const event = laAugEvents[0];
  const availableTickets = ticketTypes.filter(t => t && t.eventId === event.id && t.isAvailable === true && typeof t.price === 'number');
  availableTickets.sort((a, b) => (a.price || 0) - (b.price || 0));
  if (availableTickets.length >= 2) {
    targetTicketTypeId = availableTickets[1].id; // second-cheapest by price
  }
}

let qtyForTarget = 0;

if (targetTicketTypeId) {
  cartItems.forEach(item => {
    if (!item) return;
    if (item.itemType === 'ticket' && item.ticketTypeId === targetTicketTypeId && item.quantity > 0) {
      qtyForTarget += Number(item.quantity) || 0;
    }
  });
}

// CP1 (0.4): At least one ticket of the second-cheapest LA August 2025 type is in the cart
checkpoints.push({ passed: qtyForTarget >= 1, weight: 0.4 });

// CP2 (0.6): At least two tickets of that specific type are in the cart
checkpoints.push({ passed: qtyForTarget >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Group digital albums by albumId
const digitalByAlbum = {};
products.forEach(p => {
  if (!p) return;
  if (p.status === 'active' && p.categoryId === 'music' && p.subtype === 'digital_album' && p.albumId) {
    if (!digitalByAlbum[p.albumId]) digitalByAlbum[p.albumId] = [];
    digitalByAlbum[p.albumId].push(p);
  }
});

// Find an album that has at least two digital editions (e.g., standard + deluxe)
let albumGroup = null;
for (const albumId in digitalByAlbum) {
  if (Object.prototype.hasOwnProperty.call(digitalByAlbum, albumId)) {
    const group = digitalByAlbum[albumId];
    if (group.length >= 2) {
      albumGroup = group;
      break;
    }
  }
}

let expectedProductId = null;

if (albumGroup && albumGroup.length >= 2) {
  // Preferred edition: highest trackCount; if tie, highest price
  let preferred = albumGroup[0];
  albumGroup.forEach(p => {
    const tc = typeof p.trackCount === 'number' ? p.trackCount : 0;
    const bestTc = typeof preferred.trackCount === 'number' ? preferred.trackCount : 0;
    if (tc > bestTc) {
      preferred = p;
    } else if (tc === bestTc && (p.price || 0) > (preferred.price || 0)) {
      preferred = p;
    }
  });

  if ((preferred.price || 0) <= 20) {
    expectedProductId = preferred.id;
  } else {
    // Fallback: cheapest edition in the group (standard)
    const sorted = albumGroup.slice().sort((a, b) => (a.price || 0) - (b.price || 0));
    expectedProductId = sorted[0] ? sorted[0].id : null;
  }
}

let expectedQty = 0;
let otherGroupQty = 0;

if (expectedProductId && albumGroup) {
  const groupIds = new Set(albumGroup.map(p => p.id));
  cartItems.forEach(item => {
    if (!item) return;
    if (item.itemType === 'product' && item.productId && item.quantity > 0 && groupIds.has(item.productId)) {
      if (item.productId === expectedProductId) {
        expectedQty += Number(item.quantity) || 0;
      } else {
        otherGroupQty += Number(item.quantity) || 0;
      }
    }
  });
}

// CP1 (0.5): The correct edition (per track-count and price rule) was added to the cart
checkpoints.push({ passed: expectedQty > 0, weight: 0.5 });

// CP2 (0.5): No other digital edition of the same album was added in addition to the correct one
checkpoints.push({ passed: expectedQty > 0 && otherGroupQty === 0, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

function slugifyInterest(str) {
  if (!str) return '';
  return String(str).trim().toLowerCase().replace(/[^a-z0-9]+/g, '_');
}

const requiredSlugs = ['tour_announcements', 'new_music_releases', 'exclusive_merch_offers'];

// Subscriptions with name, email, weekly frequency, region North America, >=3 interests, and at least one required interest
const partialSubs = subs.filter(sub => {
  if (!sub) return false;
  if (!sub.name || !sub.email) return false;
  if (sub.frequency !== 'weekly') return false;
  const regionRaw = sub.region || '';
  const regionNorm = String(regionRaw).trim().toLowerCase().replace(/ /g, '_');
  if (regionNorm !== 'north_america') return false;
  if (!Array.isArray(sub.interests) || sub.interests.length < 3) return false;
  const interestSlugs = sub.interests.map(slugifyInterest);
  return requiredSlugs.some(req => interestSlugs.includes(req));
});

// Among those, subscriptions that include all three required interests
const fullSubs = partialSubs.filter(sub => {
  const interestSlugs = sub.interests.map(slugifyInterest);
  return requiredSlugs.every(req => interestSlugs.includes(req));
});

// CP1 (0.4): At least one subscription meets all non-interest criteria and includes at least one required interest
checkpoints.push({ passed: partialSubs.length > 0, weight: 0.4 });

// CP2 (0.6): At least one subscription includes all three required interests
checkpoints.push({ passed: fullSubs.length > 0, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');

let instrument = null;
try {
  const raw = localStorage.getItem('task7_openedSavedTourDiary2024Article');
  instrument = raw ? JSON.parse(raw) : null;
} catch (e) {
  instrument = null;
}

// Default reading list (or fallback by name)
let defaultList = readingLists.find(rl => rl && rl.isDefault === true);
if (!defaultList) {
  defaultList = readingLists.find(rl => (rl.name || '').toLowerCase() === 'reading list');
}

// All 2024 Tour Diary published articles
const tourDiary2024Ids = articles
  .filter(a => {
    if (!a || a.status !== 'published') return false;
    if (a.category !== 'Tour Diary') return false;
    const d = new Date(a.publishedAt);
    if (isNaN(d.getTime())) return false;
    return d.getUTCFullYear() === 2024;
  })
  .map(a => a.id);

let savedTourDiaryItems = [];
if (defaultList) {
  savedTourDiaryItems = readingListItems.filter(it => it && it.readingListId === defaultList.id && tourDiary2024Ids.includes(it.articleId));
}

// CP1 (0.5): At least three qualifying 2024 Tour Diary posts saved to the default reading list
checkpoints.push({ passed: savedTourDiaryItems.length >= 3, weight: 0.5 });

// Check that the instrumented opened article is one of the saved 2024 Tour Diary posts
let openedIsSavedTourDiary2024 = false;
if (instrument && instrument.articleId && defaultList) {
  const openedId = instrument.articleId;
  const wasSaved = savedTourDiaryItems.some(it => it.articleId === openedId);
  const art = articles.find(a => a.id === openedId);
  const is2024TourDiary = !!art && art.category === 'Tour Diary' && art.status === 'published' && (() => {
    const d = new Date(art.publishedAt);
    return !isNaN(d.getTime()) && d.getUTCFullYear() === 2024;
  })();
  openedIsSavedTourDiary2024 = wasSaved && is2024TourDiary;
}

// CP2 (0.5): The instrumented opened article was a saved 2024 Tour Diary post from the reading list
checkpoints.push({ passed: openedIsSavedTourDiary2024, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Eligible vinyls: music, vinyl_album, active, price <= 40
const vinyls = products.filter(p => {
  return p && p.status === 'active' && p.categoryId === 'music' && p.subtype === 'vinyl_album' && typeof p.price === 'number' && p.price <= 40;
});

// Sort vinyls by newest first (createdAt desc) to mirror store listing
vinyls.sort((a, b) => {
  const da = new Date(a.createdAt || 0).getTime();
  const db = new Date(b.createdAt || 0).getTime();
  return db - da;
});

const thirdVinyl = vinyls.length >= 3 ? vinyls[2] : null;

// Hoodies: apparel, hoodie, active, price <= 60
const hoodies = products.filter(p => {
  return p && p.status === 'active' && p.categoryId === 'apparel' && p.subtype === 'hoodie' && typeof p.price === 'number' && p.price <= 60;
});

// Primary hoodie: most expensive within <= 60
hoodies.sort((a, b) => (b.price || 0) - (a.price || 0));
const primaryHoodie = hoodies[0] || null;

// Fallback hoodie: under 50, choose most expensive under 50
const fallbackHoodies = hoodies.filter(h => h.price < 50);
fallbackHoodies.sort((a, b) => (b.price || 0) - (a.price || 0));
const fallbackHoodie = fallbackHoodies[0] || null;

let expectedHoodie = null;
if (thirdVinyl && primaryHoodie) {
  const bundleSubtotalPrimary = (thirdVinyl.price || 0) + (primaryHoodie.price || 0);
  if (bundleSubtotalPrimary > 100 && fallbackHoodie) {
    expectedHoodie = fallbackHoodie;
  } else {
    expectedHoodie = primaryHoodie;
  }
}

let hasThirdVinyl = false;
let hasExpectedHoodie = false;

cartItems.forEach(item => {
  if (!item || item.itemType !== 'product' || item.quantity <= 0) return;
  if (thirdVinyl && item.productId === thirdVinyl.id) {
    hasThirdVinyl = true;
  }
  if (expectedHoodie && item.productId === expectedHoodie.id) {
    hasExpectedHoodie = true;
  }
});

// CP1 (0.4): The third qualifying vinyl (<= $40) is in the cart
checkpoints.push({ passed: !!thirdVinyl && hasThirdVinyl, weight: 0.4 });

// CP2 (0.6): The third vinyl AND the correct hoodie (per bundle price rule) are both in the cart
checkpoints.push({ passed: !!thirdVinyl && !!expectedHoodie && hasThirdVinyl && hasExpectedHoodie, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
